// Script Continued Below
function onSubmit() {

	if (g_form.getActionName() == 'template_add_schedule') {	
		var saveChangeConfirmation = false;
		var saveMsg = getMessage('Tasker - Modal Save Changes Message');
		if(typeof spModal != 'undefined'){
			var serializeChanges = g_form.serialize(true);
			if(serializeChanges.length>0){
				var changeFieldList = [];
				for (var field in serializeChanges) {
					changeFieldList.push(serializeChanges[field].label.trim());
				}
				var fMsg = changeFieldList.join(', ');					
				saveMsg += "  " + fMsg;
				saveChangeConfirmation = true;
			}
		} else if (typeof spModal == 'undefined' && g_form.modified) {
			saveMsg += JSON.stringify(g_form.modifiedFields);
			saveChangeConfirmation = true;
		}

		// use the variable set above here to show confirmation message.
		if(saveChangeConfirmation){				
			if(confirm(saveMsg)){
				g_form.save();
			} else{
				return false;
			}
		}

		var title = getMessage('New Schedule');
		var view = 'Create_View';
		var formQuery = "tasker_process=" + g_form.getUniqueValue();
		var table = 'x_153465_discovert_tasker_schedule';

		// STRY0075793 - implement in Native pages also
		if (typeof spModal != 'undefined' ) {
			spModal.open({
				title: title,
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {
					table: table,
					sys_id: "-1",
					view: view,
					query: formQuery,
					omitHeader: 'true',
					isModal: true //,
				},
				size: 'lg',
				buttons: [],
				// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
				footerStyle: {
					'display': 'none'
				}
			});
			// STRY0075793 - implement in Native pages also
		}else{
			// STRY0075793
			var modalForm = new GlideModalForm(title, table);
			modalForm.addParm('sysparm_query',formQuery);
			modalForm.render();
			modalForm.setSysID(-1);
		}
		return false;
	}
}
